def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re
    TARGET_TEXT = "Left rudder causes left yaw, right rudder causes right yaw"
    PLACEHOLDER_TEXT = "Click to add text"

    prs = Presentation(modified_ppt_path)
    slide = None
    # Locate slide 11 (slide_number is 1-based)
    if len(prs.slides) < 11:
        return f"Presentation only has {len(prs.slides)} slides.", 0.0
    slide = prs.slides[10]
    found_placeholder = False
    replaced_correctly = False
    for shape in slide.shapes:
        if shape.has_text_frame:
            text = shape.text.strip()
            if text == TARGET_TEXT:
                replaced_correctly = True
            if text == PLACEHOLDER_TEXT:
                found_placeholder = True
    if replaced_correctly:
        return "Correct target text is present on slide 11.", 1.0
    if found_placeholder:
        return "Placeholder text still present on slide 11.", 0.0
    return "Target text not found, and placeholder not present. Could not verify replacement.", 0.0

def compute_score() -> tuple[str, float]:
    # Only slide 11 (slide_number=11) should be altered
    problematic_mods = []
    for (old, new) in ppt_diff.modified_slides:
        if old.slide_number != 11:
            # Check if nontrivial changes happened
            major = False
            # Check notes, title, number of elements (as proxy)
            if old.title != new.title or (old.notes or "") != (new.notes or "") or old.element_count != new.element_count:
                major = True
            if major:
                problematic_mods.append(old.slide_number)
    # Check for added/removed slides
    added = [s.slide_number for s in ppt_diff.added_slides if s.slide_number != 11]
    removed = [s.slide_number for s in ppt_diff.removed_slides if s.slide_number != 11]
    if problematic_mods or added or removed:
        return f"Slides other than 11 changed: modified={problematic_mods}, added={added}, removed={removed}.", 0.0
    return "No extraneous changes to other slides.", 1.0
